mapper.select:
SELECT /* @SQLID=SUB01-01#Sql005 */ A1.T4N_ID notificationId, A1.T4N_TITLE title, C1.T9N_NAME categoryName, A1.T4N_CONTENT contents, A1.T4N_FILE1 attachment1, A1.T4N_FILE2 attachment2, A1.T4N_FILE3 attachment3, A1.T4N_FILE_COM1 attachmentComment1, A1.T4N_FILE_COM2 attachmentComment2, A1.T4N_FILE_COM3 attachmentComment3, A1.T4N_IMPORTANCE t4nImportance, A1.T4N_URL url, A1.COR_URL_COM urlComment, A1.COR_DISCLAIMER disclaimer, CASE WHEN A1.COR_UPDATE_DATE IS NULL THEN A1.T4N_CREATED_AT ELSE A1.COR_UPDATE_DATE END updateTime, A1.T4N_CREATED_AT registerDayTime, B1.T5N_READ_FLG t5nReadFlg, B1.T5N_READ_AT readDate FROM PSITE_T4N_INFO A1 INNER JOIN PSITE_T9N_INFO_CAT C1 ON A1.T4N_CAT1 = C1.T9N_INFO_CAT LEFT OUTER JOIN ( SELECT * FROM PSITE_T5N_INFO_READ WHERE T5N_LOGIN = #{req.userId} ) B1 ON A1.T4N_ID = B1.T5N_INFO_ID
T4N_CAT1 = #{req.categoryIdCat1}
ORDER BY updateTime DESC , A1.T4N_TITLE

SELECT /* @SQLID=SUB01-01#Sql006 */ A1.T4N_ID notificationId, A1.T4N_TITLE title, C1.T9N_NAME categoryName, A1.T4N_CONTENT contents, A1.T4N_FILE1 attachment1, A1.T4N_FILE2 attachment2, A1.T4N_FILE3 attachment3, A1.T4N_FILE_COM1 attachmentComment1, A1.T4N_FILE_COM2 attachmentComment2, A1.T4N_FILE_COM3 attachmentComment3, A1.T4N_IMPORTANCE t4nImportance, A1.T4N_URL url, A1.COR_URL_COM urlComment, A1.COR_DISCLAIMER disclaimer, CASE WHEN A1.COR_UPDATE_DATE IS NULL THEN A1.T4N_CREATED_AT ELSE A1.COR_UPDATE_DATE END updateTime, A1.T4N_CREATED_AT registerDayTime, B1.T5N_READ_FLG t5nReadFlg, B1.T5N_READ_AT readDate FROM PSITE_T4N_INFO A1 INNER JOIN PSITE_T9N_INFO_CAT C1 ON A1.T4N_CAT1 = C1.T9N_INFO_CAT LEFT OUTER JOIN ( SELECT * FROM PSITE_T5N_INFO_READ WHERE T5N_LOGIN = #{req.userId} ) B1 ON A1.T4N_ID = B1.T5N_INFO_ID WHERE A1.COR_REFERENCE_CONDITION = '1'
AND T4N_CAT1 = #{req.categoryIdCat1}
UNION ALL
SELECT A2.T4N_ID notificationId, A2.T4N_TITLE title, C1.T9N_NAME categoryName, A2.T4N_CONTENT contents, A2.T4N_FILE1 attachment1, A2.T4N_FILE2 attachment2, A2.T4N_FILE3 attachment3, A2.T4N_FILE_COM1 attachmentComment1, A2.T4N_FILE_COM2 attachmentComment2, A2.T4N_FILE_COM3 attachmentComment3, A2.T4N_IMPORTANCE t4nImportance , A2.T4N_URL url, A2.COR_URL_COM urlComment, A2.COR_DISCLAIMER disclaimer, CASE WHEN A2.COR_UPDATE_DATE IS NULL THEN A2.T4N_CREATED_AT ELSE A2.COR_UPDATE_DATE END updateTime, A2.T4N_CREATED_AT registerDayTime, B2.T5N_READ_FLG t5nReadFlg, B2.T5N_READ_AT readDate FROM PSITE_T4N_INFO A2 INNER JOIN PSITE_T9N_INFO_CAT C1 ON A2.T4N_CAT1 = C1.T9N_INFO_CAT INNER JOIN PSITE_T4N_INFO_PRIV C2 ON A2.T4N_ID =C2.T4N_ID INNER JOIN TB_MED_USERS D2 ON C2.PRIV_ID = D2.PRIV_ID LEFT OUTER JOIN ( SELECT * FROM PSITE_T5N_INFO_READ WHERE T5N_LOGIN =#{req.userId} ) B2 ON A2.T4N_ID = B2.T5N_INFO_ID WHERE A2.COR_REFERENCE_CONDITION = '2'
AND T4N_CAT1 = #{req.categoryIdCat1}
AND D2.USER_ID = #{req.userId}
UNION ALL
SELECT A3.T4N_ID notificationId, A3.T4N_TITLE title, C1.T9N_NAME categoryName, A3.T4N_CONTENT contents, A3.T4N_FILE1 attachment1, A3.T4N_FILE2 attachment2, A3.T4N_FILE3 attachment3, A3.T4N_FILE_COM1 attachmentComment1, A3.T4N_FILE_COM2 attachmentComment2, A3.T4N_FILE_COM3 attachmentComment3, A3.T4N_IMPORTANCE t4nImportance, A3.T4N_URL url, A3.COR_URL_COM urlComment, A3.COR_DISCLAIMER disclaimer, CASE WHEN A3.COR_UPDATE_DATE IS NULL THEN A3.T4N_CREATED_AT ELSE A3.COR_UPDATE_DATE END updateTime, A3.T4N_CREATED_AT registerDayTime, B3.T5N_READ_FLG t5nReadFlg, B3.T5N_READ_AT readDate FROM PSITE_T4N_INFO A3 INNER JOIN PSITE_T9N_INFO_CAT C1 ON A3.T4N_CAT1 = C1.T9N_INFO_CAT INNER JOIN PSITE_T5N_INFO_READ B3 ON A3.T4N_ID = B3.T5N_INFO_ID WHERE A3.COR_REFERENCE_CONDITION = '3'
AND T4N_CAT1 = #{req.categoryIdCat1}
AND B3.T5N_LOGIN = #{req.userId}
ORDER BY updateTime DESC , title
